                parts = line.split('|')
                if len(parts) != 6:
                    continue
                event = {
                    'event_id': parts[0],
                    'name': parts[1],
                    'description': parts[2],
                    'venue_id': parts[3],
                    'date': parts[4],
                    'category': parts[5]
